import './ButtonContainer.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../helpers/classnames';
import { Button } from '../../Button';
import type { ButtonContainerProps } from './ButtonContainer.types';

export const ButtonContainer: FC<ButtonContainerProps> = ({ actions, className }) => (
	<div data-testid="ButtonContainer" className={classNames('banner-button-container', className)}>
		{actions.map(({ startIcon, label, onClick, variant }) => (
			<Button
				startIcon={startIcon}
				key={label}
				size="small"
				variant={variant ?? 'overlay'}
				onClick={onClick}
				className="banner-button"
			>
				{label}
			</Button>
		))}
	</div>
);
